429	// ----------------------------------------------------------------------------
430	// kernel launchers
431	
432	// similar to `fused_residual_forward5`
433	void layernorm_forward(floatX* out, float* mean, float* rstd,
434	                       floatX* inp, const floatX* weight, const floatX* bias,
435	                       int B, int T, int C, cudaStream_t stream) {
436	    NVTX_RANGE_FN();
437	    const int block_size = 256;
438	    int block_y = block_size / WARP_SIZE;
439	    const int N = B * T;
440	    const int grid_size = CEIL_DIV(N, block_y);
441	    size_t smem = (2 + block_y) * C * sizeof(floatX);
442	
443	    // in order to use more than 48 KiB of smem, need to call cudaFuncSetAttribute
444	    // this may fail, in which case we fall back to the smem free implementation.
445	    cudaCheck(cudaGetLastError());
446	    auto status = cudaFuncSetAttribute(layernorm_forward_kernel6, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);
447	    cudaCheck(cudaGetLastError());
448	    if (status == cudaSuccess) {
449	        layernorm_forward_kernel6<<<grid_size, dim3(WARP_SIZE, block_y), smem, stream>>>(out, mean, rstd, inp, weight, bias, N, C);
450	    } else {
451	        // fall back to the version without shared memory
452	        const int grid_size_fb = CEIL_DIV(N * WARP_SIZE, block_size);
453	        layernorm_forward_kernel3<<<grid_size_fb, block_size, 0, stream>>>(out, mean, rstd, inp, weight, bias, N, C);
454	    }
455	    cudaCheck(cudaGetLastError());
456	}
457	
458	void residual_forward(floatX* out, const floatX* inp1, const floatX* inp2, int N, cudaStream_t stream) {
459	    NVTX_RANGE_FN();
460	    const int block_size = 256;
461	    assert(N % (block_size * x128::size) == 0);
462	    const int grid_size = CEIL_DIV(N, block_size * x128::size);
463	    residual_forward_kernel<<<grid_size, block_size, 0, stream>>>(out, inp1, inp2);
464	    cudaCheck(cudaGetLastError());
465	}
