467	void fused_residual_forward5(floatX* residual, floatX* normed, float* mean, float* rstd,
468	                             const floatX* inp1, const floatX* inp2,
469	                             const floatX* weight, const floatX* bias,
470	                             int N, int C, cudaStream_t stream) {
471	    const int block_size = 256;
472	    int block_y = block_size / WARP_SIZE;
473	    const int grid_size = CEIL_DIV(N, block_y);
474	    size_t smem = (2 + block_y) * C * sizeof(floatX);
475	
476	    // in order to use more than 48 KiB of smem, need to call cudaFuncSetAttribute
477	    // this may fail, in which case we fall back to the smem free implementation.
478	    cudaCheck(cudaGetLastError());
479	    auto status = cudaFuncSetAttribute(fused_residual_forward_kernel5, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);
480	    cudaCheck(cudaGetLastError());
481	    if(status == cudaSuccess) {
482	        fused_residual_forward_kernel5<<<grid_size, dim3(WARP_SIZE, block_y), smem, stream>>>(residual, normed,
483	                                                                                              mean, rstd, inp1, inp2,
484	                                                                                              weight, bias, N, C);
485	    } else {
486	        residual_forward(residual, inp1, inp2, N*C, stream);
487	        layernorm_forward(normed, mean, rstd, residual, weight, bias, N, 1, C, stream);
488	    }
489	    cudaCheck(cudaGetLastError());
490	}
491	
492	void layernorm_backward(floatX* dinp, floatX* dweight, floatX* dbias, float* scratch,
493	                        const floatX* dout, const floatX* inp, const floatX* weight, const float* mean, const float* rstd,
494	                        int B, int T, int C, cudaStream_t stream) {
495	    NVTX_RANGE_FN();
496	    const int block_size = 512;
497	    const int blocks_per_sm = 2; // supported on every architecture and less cache thrashing than 3
498	    const int grid_size = blocks_per_sm * deviceProp.multiProcessorCount;
499	    size_t rounded_C = CEIL_DIV(C, (32 * x128::size)) * (32 * x128::size);
500	    size_t shared_mem_size = (2 * rounded_C + 2 * (block_size - 32) * f128::size) * sizeof(float);
501	
502	    cudaCheck(cudaMemsetAsync(scratch, 0, 1 * sizeof(float), stream)); // only need to reset the flag to 0
503	    layernorm_backward_kernel10<<<grid_size, block_size, shared_mem_size, stream>>>(dinp, dweight, dbias, scratch, dout, inp, weight, mean, rstd, B, T, C);
504	    cudaCheck(cudaGetLastError());
505	}
